mapper.select:
SELECT cl.*, m.major_name, m.college_id, c.college_name FROM edu_class cl LEFT JOIN edu_major m ON cl.major_id = m.id LEFT JOIN edu_college c ON m.college_id = c.id
AND cl.class_name LIKE CONCAT('%', #{className}, '%')
AND cl.major_id = #{majorId}
AND m.college_id = #{collegeId}
AND cl.enrollment_year = #{enrollmentYear}
AND cl.status = #{status}
ORDER BY cl.enrollment_year DESC, cl.class_name ASC

mapper.delete:
DELETE FROM edu_class 
WHERE id IN

    #{id}

mapper.select:
SELECT COUNT(1) 
FROM edu_class 
WHERE class_name = #{className}

    AND id != #{excludeId}
